func (o *NonIpProtocol) matches(other *NonIpProtocol) bool {
	if o == nil && other == nil {
		return true
	}

	if (o == nil && other != nil) || (o != nil && other == nil) {
		return false
	}
	if !util.StringsMatch(o.ListType, other.ListType) {
		return false
	}
	if len(o.Protocol) != len(other.Protocol) {
		return false
	}
	for idx := range o.Protocol {
		if !o.Protocol[idx].matches(&other.Protocol[idx]) {
			return false
		}
	}

	return true
}

